     1→//! `render` module provides utilities for rendering completion suggestions
     2→//! into code pieces that will be presented to user.
     3→
     4→pub(crate) mod const_;
     5→pub(crate) mod function;
     6→pub(crate) mod literal;
     7→pub(crate) mod macro_;
     8→pub(crate) mod pattern;
     9→pub(crate) mod type_alias;
    10→pub(crate) mod union_literal;
    11→pub(crate) mod variant;
    12→
    13→use hir::{AsAssocItem, HasAttrs, HirDisplay, ModuleDef, ScopeDef, Type, sym};
    14→use ide_db::text_edit::TextEdit;
    15→use ide_db::{
    16→    RootDatabase, SnippetCap, SymbolKind,
    17→    documentation::{Documentation, HasDocs},
    18→    helpers::item_name,
    19→    imports::import_assets::LocatedImport,
    20→};
    21→use syntax::{AstNode, SmolStr, SyntaxKind, TextRange, ToSmolStr, ast, format_smolstr};
    22→
    23→use crate::{
    24→    CompletionContext, CompletionItem, CompletionItemKind, CompletionItemRefMode,
    25→    CompletionRelevance,
    26→    context::{DotAccess, DotAccessKind, PathCompletionCtx, PathKind, PatternContext},
    27→    item::{Builder, CompletionRelevanceTypeMatch},
    28→    render::{
    29→        function::render_fn,
    30→        literal::render_variant_lit,
    31→        macro_::{render_macro, render_macro_pat},
    32→    },
    33→};
    34→/// Interface for data and methods required for items rendering.
    35→#[derive(Debug, Clone)]
    36→pub(crate) struct RenderContext<'a> {
    37→    completion: &'a CompletionContext<'a>,
    38→    is_private_editable: bool,
    39→    import_to_add: Option<LocatedImport>,
    40→    doc_aliases: Vec<SmolStr>,
    41→}
    42→
    43→impl<'a> RenderContext<'a> {
    44→    pub(crate) fn new(completion: &'a CompletionContext<'a>) -> RenderContext<'a> {
    45→        RenderContext {
    46→            completion,
    47→            is_private_editable: false,
    48→            import_to_add: None,
    49→            doc_aliases: vec![],
    50→        }
    51→    }
    52→
    53→    pub(crate) fn private_editable(mut self, private_editable: bool) -> Self {
    54→        self.is_private_editable = private_editable;
    55→        self
    56→    }
    57→
    58→    pub(crate) fn import_to_add(mut self, import_to_add: Option<LocatedImport>) -> Self {
    59→        self.import_to_add = import_to_add;
    60→        self
    61→    }
    62→
    63→    pub(crate) fn doc_aliases(mut self, doc_aliases: Vec<SmolStr>) -> Self {
    64→        self.doc_aliases = doc_aliases;
    65→        self
    66→    }
    67→
    68→    fn snippet_cap(&self) -> Option<SnippetCap> {
    69→        self.completion.config.snippet_cap
    70→    }
    71→
    72→    fn db(&self) -> &'a RootDatabase {
    73→        self.completion.db
    74→    }
    75→
    76→    fn source_range(&self) -> TextRange {
    77→        self.completion.source_range()
    78→    }
    79→
    80→    fn completion_relevance(&self) -> CompletionRelevance {
    81→        CompletionRelevance {
    82→            is_private_editable: self.is_private_editable,
    83→            requires_import: self.import_to_add.is_some(),
    84→            ..Default::default()
    85→        }
    86→    }
    87→
    88→    fn is_immediately_after_macro_bang(&self) -> bool {
    89→        self.completion.token.kind() == SyntaxKind::BANG
    90→            && self.completion.token.parent().is_some_and(|it| it.kind() == SyntaxKind::MACRO_CALL)
    91→    }
    92→
    93→    fn is_deprecated(&self, def: impl HasAttrs) -> bool {
    94→        let attrs = def.attrs(self.db());
    95→        attrs.by_key(sym::deprecated).exists()
    96→    }
    97→
    98→    fn is_deprecated_assoc_item(&self, as_assoc_item: impl AsAssocItem) -> bool {
    99→        let db = self.db();
   100→        let assoc = match as_assoc_item.as_assoc_item(db) {
   101→            Some(assoc) => assoc,
   102→            None => return false,
   103→        };
   104→
   105→        let is_assoc_deprecated = match assoc {
   106→            hir::AssocItem::Function(it) => self.is_deprecated(it),
   107→            hir::AssocItem::Const(it) => self.is_deprecated(it),
   108→            hir::AssocItem::TypeAlias(it) => self.is_deprecated(it),
   109→        };
   110→        is_assoc_deprecated
   111→            || assoc
   112→                .container_or_implemented_trait(db)
   113→                .map(|trait_| self.is_deprecated(trait_))
   114→                .unwrap_or(false)
   115→    }
   116→
   117→    // FIXME: remove this
   118→    fn docs(&self, def: impl HasDocs) -> Option<Documentation> {
   119→        def.docs(self.db())
   120→    }
   121→}
   122→
   123→pub(crate) fn render_field(
   124→    ctx: RenderContext<'_>,
   125→    dot_access: &DotAccess<'_>,
   126→    receiver: Option<SmolStr>,
   127→    field: hir::Field,
   128→    ty: &hir::Type<'_>,
   129→) -> CompletionItem {
   130→    let db = ctx.db();
   131→    let is_deprecated = ctx.is_deprecated(field);
   132→    let name = field.name(db);
   133→    let (name, escaped_name) =
   134→        (name.as_str().to_smolstr(), name.display_no_db(ctx.completion.edition).to_smolstr());
   135→    let mut item = CompletionItem::new(
   136→        SymbolKind::Field,
   137→        ctx.source_range(),
   138→        field_with_receiver(receiver.as_deref(), &name),
   139→        ctx.completion.edition,
   140→    );
   141→    item.set_relevance(CompletionRelevance {
   142→        type_match: compute_type_match(ctx.completion, ty),
   143→        exact_name_match: compute_exact_name_match(ctx.completion, &name),
   144→        is_skipping_completion: receiver.is_some(),
   145→        ..CompletionRelevance::default()
   146→    });
   147→    item.detail(ty.display(db, ctx.completion.display_target).to_string())
   148→        .set_documentation(field.docs(db))
   149→        .set_deprecated(is_deprecated)
   150→        .lookup_by(name);
   151→
   152→    let is_field_access = matches!(dot_access.kind, DotAccessKind::Field { .. });
   153→    if !is_field_access || ty.is_fn() || ty.is_closure() {
   154→        let mut builder = TextEdit::builder();
   155→        // Using TextEdit, insert '(' before the struct name and ')' before the
   156→        // dot access, then comes the field name and optionally insert function
   157→        // call parens.
   158→
   159→        builder.replace(
   160→            ctx.source_range(),
   161→            field_with_receiver(receiver.as_deref(), &escaped_name).into(),
   162→        );
   163→
   164→        let expected_fn_type =
   165→            ctx.completion.expected_type.as_ref().is_some_and(|ty| ty.is_fn() || ty.is_closure());
   166→
   167→        if !expected_fn_type
   168→            && let Some(receiver) = &dot_access.receiver
   169→            && let Some(receiver) = ctx.completion.sema.original_ast_node(receiver.clone())
   170→        {
   171→            builder.insert(receiver.syntax().text_range().start(), "(".to_owned());
   172→            builder.insert(ctx.source_range().end(), ")".to_owned());
   173→
   174→            let is_parens_needed =
   175→                !matches!(dot_access.kind, DotAccessKind::Method { has_parens: true });
   176→
   177→            if is_parens_needed {
   178→                builder.insert(ctx.source_range().end(), "()".to_owned());
   179→            }
   180→        }
   181→
   182→        item.text_edit(builder.finish());
   183→    } else {
   184→        item.insert_text(field_with_receiver(receiver.as_deref(), &escaped_name));
   185→    }
   186→    if let Some(receiver) = &dot_access.receiver
   187→        && let Some(original) = ctx.completion.sema.original_ast_node(receiver.clone())
   188→        && let Some(ref_mode) = compute_ref_match(ctx.completion, ty)
   189→    {
   190→        item.ref_match(ref_mode, original.syntax().text_range().start());
   191→    }
   192→    item.doc_aliases(ctx.doc_aliases);
   193→    item.build(db)
   194→}
   195→
   196→fn field_with_receiver(receiver: Option<&str>, field_name: &str) -> SmolStr {
   197→    receiver
   198→        .map_or_else(|| field_name.into(), |receiver| format_smolstr!("{}.{field_name}", receiver))
   199→}
   200→
   201→pub(crate) fn render_tuple_field(
   202→    ctx: RenderContext<'_>,
   203→    receiver: Option<SmolStr>,
   204→    field: usize,
   205→    ty: &hir::Type<'_>,
   206→) -> CompletionItem {
   207→    let mut item = CompletionItem::new(
   208→        SymbolKind::Field,
   209→        ctx.source_range(),
   210→        field_with_receiver(receiver.as_deref(), &field.to_string()),
   211→        ctx.completion.edition,
   212→    );
   213→    item.detail(ty.display(ctx.db(), ctx.completion.display_target).to_string())
   214→        .lookup_by(field.to_string());
   215→    item.set_relevance(CompletionRelevance {
   216→        is_skipping_completion: receiver.is_some(),
   217→        ..ctx.completion_relevance()
   218→    });
   219→    item.build(ctx.db())
   220→}
