   280→
   281→pub(crate) fn render_expr(
   282→    ctx: &CompletionContext<'_>,
   283→    expr: &hir::term_search::Expr<'_>,
   284→) -> Option<Builder> {
   285→    let mut i = 1;
   286→    let mut snippet_formatter = |ty: &hir::Type<'_>| {
   287→        let arg_name = ty
   288→            .as_adt()
   289→            .map(|adt| stdx::to_lower_snake_case(adt.name(ctx.db).as_str()))
   290→            .unwrap_or_else(|| String::from("_"));
   291→        let res = format!("${{{i}:{arg_name}}}");
   292→        i += 1;
   293→        res
   294→    };
   295→
   296→    let mut label_formatter = |ty: &hir::Type<'_>| {
   297→        ty.as_adt()
   298→            .map(|adt| stdx::to_lower_snake_case(adt.name(ctx.db).as_str()))
   299→            .unwrap_or_else(|| String::from("..."))
   300→    };
   301→
   302→    let cfg = ctx.config.import_path_config(ctx.is_nightly);
   303→
   304→    let label =
   305→        expr.gen_source_code(&ctx.scope, &mut label_formatter, cfg, ctx.display_target).ok()?;
   306→
   307→    let source_range = match ctx.original_token.parent() {
   308→        Some(node) => match node.ancestors().find_map(ast::Path::cast) {
   309→            Some(path) => path.syntax().text_range(),
   310→            None => node.text_range(),
   311→        },
   312→        None => ctx.source_range(),
   313→    };
   314→
   315→    let mut item =
   316→        CompletionItem::new(CompletionItemKind::Expression, source_range, label, ctx.edition);
   317→
   318→    let snippet = format!(
   319→        "{}$0",
   320→        expr.gen_source_code(&ctx.scope, &mut snippet_formatter, cfg, ctx.display_target).ok()?
   321→    );
   322→    let edit = TextEdit::replace(source_range, snippet);
   323→    item.snippet_edit(ctx.config.snippet_cap?, edit);
   324→    item.documentation(Documentation::new(String::from("Autogenerated expression by term search")));
   325→    item.set_relevance(crate::CompletionRelevance {
   326→        type_match: compute_type_match(ctx, &expr.ty(ctx.db)),
   327→        ..Default::default()
   328→    });
   329→    for trait_ in expr.traits_used(ctx.db) {
   330→        let trait_item = hir::ItemInNs::from(hir::ModuleDef::from(trait_));
   331→        let Some(path) = ctx.module.find_path(ctx.db, trait_item, cfg) else {
   332→            continue;
   333→        };
   334→
   335→        item.add_import(LocatedImport::new_no_completion(path, trait_item, trait_item));
   336→    }
   337→
   338→    Some(item)
   339→}
   340→
   341→fn get_import_name(
   342→    resolution: ScopeDef,
   343→    ctx: &RenderContext<'_>,
   344→    import_edit: &LocatedImport,
   345→) -> Option<hir::Name> {
   346→    // FIXME: Temporary workaround for handling aliased import.
   347→    // This should be removed after we have proper support for importing alias.
   348→    // <https://github.com/rust-lang/rust-analyzer/issues/14079>
   349→
   350→    // If `item_to_import` matches `original_item`, we are importing the item itself (not its parent module).
   351→    // In this case, we can use the last segment of `import_path`, as it accounts for the aliased name.
   352→    if import_edit.item_to_import == import_edit.original_item {
   353→        import_edit.import_path.segments().last().cloned()
   354→    } else {
   355→        scope_def_to_name(resolution, ctx, import_edit)
   356→    }
   357→}
   358→
   359→fn scope_def_to_name(
   360→    resolution: ScopeDef,
   361→    ctx: &RenderContext<'_>,
   362→    import_edit: &LocatedImport,
   363→) -> Option<hir::Name> {
   364→    Some(match resolution {
   365→        ScopeDef::ModuleDef(hir::ModuleDef::Function(f)) => f.name(ctx.completion.db),
   366→        ScopeDef::ModuleDef(hir::ModuleDef::Const(c)) => c.name(ctx.completion.db)?,
   367→        ScopeDef::ModuleDef(hir::ModuleDef::TypeAlias(t)) => t.name(ctx.completion.db),
   368→        _ => item_name(ctx.db(), import_edit.original_item)?,
   369→    })
   370→}
   371→
   372→fn render_resolution_pat(
   373→    ctx: RenderContext<'_>,
   374→    pattern_ctx: &PatternContext,
   375→    local_name: hir::Name,
   376→    import_to_add: Option<LocatedImport>,
   377→    resolution: ScopeDef,
   378→) -> Builder {
   379→    let _p = tracing::info_span!("render_resolution_pat").entered();
   380→    use hir::ModuleDef::*;
   381→
   382→    if let ScopeDef::ModuleDef(Macro(mac)) = resolution {
   383→        let ctx = ctx.import_to_add(import_to_add);
   384→        render_macro_pat(ctx, pattern_ctx, local_name, mac)
   385→    } else {
   386→        render_resolution_simple_(ctx, &local_name, import_to_add, resolution)
   387→    }
   388→}
   389→
   390→fn render_resolution_path(
   391→    ctx: RenderContext<'_>,
   392→    path_ctx: &PathCompletionCtx<'_>,
   393→    local_name: hir::Name,
   394→    import_to_add: Option<LocatedImport>,
   395→    resolution: ScopeDef,
   396→) -> Builder {
   397→    let _p = tracing::info_span!("render_resolution_path").entered();
   398→    use hir::ModuleDef::*;
   399→
   400→    let krate = ctx.completion.display_target;
   401→
   402→    match resolution {
   403→        ScopeDef::ModuleDef(Macro(mac)) => {
   404→            let ctx = ctx.import_to_add(import_to_add);
   405→            return render_macro(ctx, path_ctx, local_name, mac);
   406→        }
   407→        ScopeDef::ModuleDef(Function(func)) => {
   408→            let ctx = ctx.import_to_add(import_to_add);
   409→            return render_fn(ctx, path_ctx, Some(local_name), func);
   410→        }
   411→        ScopeDef::ModuleDef(Variant(var)) => {
   412→            let ctx = ctx.clone().import_to_add(import_to_add.clone());
   413→            if let Some(item) =
   414→                render_variant_lit(ctx, path_ctx, Some(local_name.clone()), var, None)
   415→            {
   416→                return item;
   417→            }
   418→        }
   419→        _ => (),
   420→    }
   421→
   422→    let completion = ctx.completion;
   423→    let cap = ctx.snippet_cap();
   424→    let db = completion.db;
   425→    let config = completion.config;
   426→    let requires_import = import_to_add.is_some();
   427→
   428→    let name = local_name.display_no_db(ctx.completion.edition).to_smolstr();
   429→    let mut item = render_resolution_simple_(ctx, &local_name, import_to_add, resolution);
   430→    if local_name.needs_escape(completion.edition) {
   431→        item.insert_text(local_name.display_no_db(completion.edition).to_smolstr());
   432→    }
   433→    // Add `<>` for generic types
   434→    let type_path_no_ty_args = matches!(
   435→        path_ctx,
   436→        PathCompletionCtx { kind: PathKind::Type { .. }, has_type_args: false, .. }
   437→    ) && config.callable.is_some();
   438→    if type_path_no_ty_args && let Some(cap) = cap {
   439→        let has_non_default_type_params = match resolution {
   440→            ScopeDef::ModuleDef(hir::ModuleDef::Adt(it)) => it.has_non_default_type_params(db),
   441→            ScopeDef::ModuleDef(hir::ModuleDef::TypeAlias(it)) => {
   442→                it.has_non_default_type_params(db)
   443→            }
   444→            _ => false,
   445→        };
   446→
   447→        if has_non_default_type_params {
   448→            cov_mark::hit!(inserts_angle_brackets_for_generics);
   449→            item.lookup_by(name.clone())
   450→                .label(SmolStr::from_iter([&name, "<…>"]))
   451→                .trigger_call_info()
   452→                .insert_snippet(cap, format!("{}<$0>", local_name.display(db, completion.edition)));
   453→        }
   454→    }
   455→
   456→    let mut set_item_relevance = |ty: Type<'_>| {
   457→        if !ty.is_unknown() {
   458→            item.detail(ty.display(db, krate).to_string());
   459→        }
   460→
   461→        item.set_relevance(CompletionRelevance {
   462→            type_match: compute_type_match(completion, &ty),
   463→            exact_name_match: compute_exact_name_match(completion, &name),
   464→            is_local: matches!(resolution, ScopeDef::Local(_)),
   465→            requires_import,
   466→            ..CompletionRelevance::default()
   467→        });
   468→
   469→        path_ref_match(completion, path_ctx, &ty, &mut item);
   470→    };
   471→
   472→    match resolution {
   473→        ScopeDef::Local(local) => set_item_relevance(local.ty(db)),
   474→        ScopeDef::ModuleDef(ModuleDef::Adt(adt)) | ScopeDef::AdtSelfType(adt) => {
   475→            set_item_relevance(adt.ty(db))
   476→        }
   477→        // Filtered out above
   478→        ScopeDef::ModuleDef(
   479→            ModuleDef::Function(_) | ModuleDef::Variant(_) | ModuleDef::Macro(_),
   480→        ) => (),
   481→        ScopeDef::ModuleDef(ModuleDef::Const(konst)) => set_item_relevance(konst.ty(db)),
   482→        ScopeDef::ModuleDef(ModuleDef::Static(stat)) => set_item_relevance(stat.ty(db)),
   483→        ScopeDef::ModuleDef(ModuleDef::BuiltinType(bt)) => set_item_relevance(bt.ty(db)),
   484→        ScopeDef::ImplSelfType(imp) => set_item_relevance(imp.self_ty(db)),
   485→        ScopeDef::GenericParam(_)
   486→        | ScopeDef::Label(_)
   487→        | ScopeDef::Unknown
   488→        | ScopeDef::ModuleDef(
   489→            ModuleDef::Trait(_)
   490→            | ModuleDef::TraitAlias(_)
   491→            | ModuleDef::Module(_)
   492→            | ModuleDef::TypeAlias(_),
   493→        ) => (),
   494→    };
   495→
   496→    item
   497→}
   498→
   499→fn render_resolution_simple_(
   500→    ctx: RenderContext<'_>,
   501→    local_name: &hir::Name,
   502→    import_to_add: Option<LocatedImport>,
   503→    resolution: ScopeDef,
   504→) -> Builder {
   505→    let _p = tracing::info_span!("render_resolution_simple_").entered();
   506→
   507→    let db = ctx.db();
   508→    let ctx = ctx.import_to_add(import_to_add);
   509→    let kind = res_to_kind(resolution);
   510→
   511→    let mut item = CompletionItem::new(
   512→        kind,
   513→        ctx.source_range(),
   514→        local_name.as_str().to_smolstr(),
   515→        ctx.completion.edition,
   516→    );
   517→    item.set_relevance(ctx.completion_relevance())
   518→        .set_documentation(scope_def_docs(db, resolution))
   519→        .set_deprecated(scope_def_is_deprecated(&ctx, resolution));
   520→
   521→    if let Some(import_to_add) = ctx.import_to_add {
   522→        item.add_import(import_to_add);
   523→    }
   524→
   525→    item.doc_aliases(ctx.doc_aliases);
   526→    item
   527→}
   528→
   529→fn res_to_kind(resolution: ScopeDef) -> CompletionItemKind {
   530→    use hir::ModuleDef::*;
   531→    match resolution {
   532→        ScopeDef::Unknown => CompletionItemKind::UnresolvedReference,
   533→        ScopeDef::ModuleDef(Function(_)) => CompletionItemKind::SymbolKind(SymbolKind::Function),
   534→        ScopeDef::ModuleDef(Variant(_)) => CompletionItemKind::SymbolKind(SymbolKind::Variant),
   535→        ScopeDef::ModuleDef(Macro(_)) => CompletionItemKind::SymbolKind(SymbolKind::Macro),
   536→        ScopeDef::ModuleDef(Module(..)) => CompletionItemKind::SymbolKind(SymbolKind::Module),
   537→        ScopeDef::ModuleDef(Adt(adt)) => CompletionItemKind::SymbolKind(match adt {
   538→            hir::Adt::Struct(_) => SymbolKind::Struct,
   539→            hir::Adt::Union(_) => SymbolKind::Union,
   540→            hir::Adt::Enum(_) => SymbolKind::Enum,
   541→        }),
   542→        ScopeDef::ModuleDef(Const(..)) => CompletionItemKind::SymbolKind(SymbolKind::Const),
   543→        ScopeDef::ModuleDef(Static(..)) => CompletionItemKind::SymbolKind(SymbolKind::Static),
   544→        ScopeDef::ModuleDef(Trait(..)) => CompletionItemKind::SymbolKind(SymbolKind::Trait),
   545→        ScopeDef::ModuleDef(TraitAlias(..)) => {
   546→            CompletionItemKind::SymbolKind(SymbolKind::TraitAlias)
   547→        }
   548→        ScopeDef::ModuleDef(TypeAlias(..)) => CompletionItemKind::SymbolKind(SymbolKind::TypeAlias),
   549→        ScopeDef::ModuleDef(BuiltinType(..)) => CompletionItemKind::BuiltinType,
   550→        ScopeDef::GenericParam(param) => CompletionItemKind::SymbolKind(match param {
   551→            hir::GenericParam::TypeParam(_) => SymbolKind::TypeParam,
   552→            hir::GenericParam::ConstParam(_) => SymbolKind::ConstParam,
   553→            hir::GenericParam::LifetimeParam(_) => SymbolKind::LifetimeParam,
   554→        }),
   555→        ScopeDef::Local(..) => CompletionItemKind::SymbolKind(SymbolKind::Local),
   556→        ScopeDef::Label(..) => CompletionItemKind::SymbolKind(SymbolKind::Label),
   557→        ScopeDef::AdtSelfType(..) | ScopeDef::ImplSelfType(..) => {
   558→            CompletionItemKind::SymbolKind(SymbolKind::SelfParam)
   559→        }
   560→    }
   561→}
   562→
   563→fn scope_def_docs(db: &RootDatabase, resolution: ScopeDef) -> Option<Documentation> {
   564→    use hir::ModuleDef::*;
   565→    match resolution {
   566→        ScopeDef::ModuleDef(Module(it)) => it.docs(db),
   567→        ScopeDef::ModuleDef(Adt(it)) => it.docs(db),
   568→        ScopeDef::ModuleDef(Variant(it)) => it.docs(db),
   569→        ScopeDef::ModuleDef(Const(it)) => it.docs(db),
   570→        ScopeDef::ModuleDef(Static(it)) => it.docs(db),
   571→        ScopeDef::ModuleDef(Trait(it)) => it.docs(db),
   572→        ScopeDef::ModuleDef(TypeAlias(it)) => it.docs(db),
   573→        _ => None,
   574→    }
   575→}
   576→
   577→fn scope_def_is_deprecated(ctx: &RenderContext<'_>, resolution: ScopeDef) -> bool {
   578→    match resolution {
   579→        ScopeDef::ModuleDef(it) => ctx.is_deprecated_assoc_item(it),
   580→        ScopeDef::GenericParam(it) => ctx.is_deprecated(it),
   581→        ScopeDef::AdtSelfType(it) => ctx.is_deprecated(it),
   582→        _ => false,
   583→    }
   584→}
   585→
   586→// FIXME: This checks types without possible coercions which some completions might want to do
   587→fn match_types(
   588→    ctx: &CompletionContext<'_>,
   589→    ty1: &hir::Type<'_>,
   590→    ty2: &hir::Type<'_>,
   591→) -> Option<CompletionRelevanceTypeMatch> {
   592→    if ty1 == ty2 {
   593→        Some(CompletionRelevanceTypeMatch::Exact)
   594→    } else if ty1.could_unify_with(ctx.db, ty2) {
   595→        Some(CompletionRelevanceTypeMatch::CouldUnify)
   596→    } else {
   597→        None
   598→    }
   599→}
   600→
   601→fn compute_type_match(
   602→    ctx: &CompletionContext<'_>,
   603→    completion_ty: &hir::Type<'_>,
   604→) -> Option<CompletionRelevanceTypeMatch> {
   605→    let expected_type = ctx.expected_type.as_ref()?;
   606→
   607→    // We don't ever consider unit type to be an exact type match, since
   608→    // nearly always this is not meaningful to the user.
   609→    if expected_type.is_unit() {
   610→        return None;
   611→    }
   612→
   613→    match_types(ctx, expected_type, completion_ty)
   614→}
   615→
   616→fn compute_exact_name_match(ctx: &CompletionContext<'_>, completion_name: &str) -> bool {
   617→    ctx.expected_name.as_ref().is_some_and(|name| name.text() == completion_name)
   618→}
   619→
   620→fn compute_ref_match(
   621→    ctx: &CompletionContext<'_>,
   622→    completion_ty: &hir::Type<'_>,
   623→) -> Option<CompletionItemRefMode> {
   624→    let expected_type = ctx.expected_type.as_ref()?;
   625→    let expected_without_ref = expected_type.remove_ref();
   626→    let completion_without_ref = completion_ty.remove_ref();
   627→    if expected_type.could_unify_with(ctx.db, completion_ty) {
   628→        return None;
   629→    }
   630→    if let Some(expected_without_ref) = &expected_without_ref
   631→        && completion_ty.autoderef(ctx.db).any(|ty| ty == *expected_without_ref)
   632→    {
   633→        cov_mark::hit!(suggest_ref);
   634→        let mutability = if expected_type.is_mutable_reference() {
   635→            hir::Mutability::Mut
   636→        } else {
   637→            hir::Mutability::Shared
   638→        };
   639→        return Some(CompletionItemRefMode::Reference(mutability));
   640→    }
   641→
   642→    if let Some(completion_without_ref) = completion_without_ref
   643→        && completion_without_ref == *expected_type
   644→        && completion_without_ref.is_copy(ctx.db)
   645→    {
   646→        cov_mark::hit!(suggest_deref);
   647→        return Some(CompletionItemRefMode::Dereference);
   648→    }
   649→
   650→    None
   651→}
   652→
   653→fn path_ref_match(
   654→    completion: &CompletionContext<'_>,
   655→    path_ctx: &PathCompletionCtx<'_>,
   656→    ty: &hir::Type<'_>,
   657→    item: &mut Builder,
   658→) {
   659→    if let Some(original_path) = &path_ctx.original_path {
   660→        // At least one char was typed by the user already, in that case look for the original path
   661→        if let Some(original_path) = completion.sema.original_ast_node(original_path.clone())
   662→            && let Some(ref_mode) = compute_ref_match(completion, ty)
   663→        {
   664→            item.ref_match(ref_mode, original_path.syntax().text_range().start());
   665→        }
   666→    } else {
   667→        // completion requested on an empty identifier, there is no path here yet.
   668→        // FIXME: This might create inconsistent completions where we show a ref match in macro inputs
   669→        // as long as nothing was typed yet
   670→        if let Some(ref_mode) = compute_ref_match(completion, ty) {
   671→            item.ref_match(ref_mode, completion.position.offset);
   672→        }
   673→    }
   674→}
