   744→    #[track_caller]
   745→    fn check_relevance_(actual: Vec<CompletionItem>, expect: Expect) {
   746→        let actual = actual
   747→            .into_iter()
   748→            .flat_map(|it| {
   749→                let mut items = vec![];
   750→
   751→                let tag = it.kind.tag();
   752→                let relevance = display_relevance(it.relevance);
   753→                items.push(format!(
   754→                    "{tag} {} {} {relevance}\n",
   755→                    it.label.primary,
   756→                    it.label.detail_right.clone().unwrap_or_default(),
   757→                ));
   758→
   759→                if let Some((label, _indel, relevance)) = it.ref_match() {
   760→                    let relevance = display_relevance(relevance);
   761→
   762→                    items.push(format!("{tag} {label} {relevance}\n"));
   763→                }
   764→
   765→                items
   766→            })
   767→            .collect::<String>();
   768→
   769→        expect.assert_eq(&actual);
   770→
   771→        fn display_relevance(relevance: CompletionRelevance) -> String {
   772→            let relevance_factors = vec![
   773→                (relevance.type_match == Some(CompletionRelevanceTypeMatch::Exact), "type"),
   774→                (
   775→                    relevance.type_match == Some(CompletionRelevanceTypeMatch::CouldUnify),
   776→                    "type_could_unify",
   777→                ),
   778→                (relevance.exact_name_match, "name"),
   779→                (relevance.is_local, "local"),
   780→                (
   781→                    relevance.postfix_match == Some(CompletionRelevancePostfixMatch::Exact),
   782→                    "snippet",
   783→                ),
   784→                (relevance.trait_.is_some_and(|it| it.is_op_method), "op_method"),
   785→                (relevance.requires_import, "requires_import"),
   786→            ]
   787→            .into_iter()
   788→            .filter_map(|(cond, desc)| if cond { Some(desc) } else { None })
   789→            .join("+");
   790→
   791→            format!("[{relevance_factors}]")
   792→        }
   793→    }
