   807→fn classify_name_ref<'db>(
   808→    sema: &Semantics<'db, RootDatabase>,
   809→    original_file: &SyntaxNode,
   810→    name_ref: ast::NameRef,
   811→    original_offset: TextSize,
   812→    parent: SyntaxNode,
   813→) -> Option<(NameRefContext<'db>, QualifierCtx)> {
