fn call_parens_with_newline() {
    check_edit(
        "foo",
        r#"
fn foo(v: i32) {}

fn bar() {
    foo$0
    ()
}
    "#,
        r#"
fn foo(v: i32) {}

fn bar() {
    foo(${1:v});$0
    ()
}
    "#,
    );
    check_edit(
        "foo",
        r#"
struct Foo;
impl Foo {
    fn foo(&self, v: i32) {}
}

fn bar() {
    Foo.foo$0
    ()
}
    "#,
        r#"
struct Foo;
impl Foo {
    fn foo(&self, v: i32) {}
}

fn bar() {
    Foo.foo(${1:v});$0
    ()
}
    "#,
    );
}

#[test]
fn dbg_too_many_asterisks() {
    check_edit(
        "dbg",
        r#"
fn main() {
    let x = &42;
    let y = *x.$0;
}
    "#,
        r#"
fn main() {
    let x = &42;
    let y = dbg!(*x);
}
    "#,
    );
}

#[test]
fn ambiguous_float_literal() {
    check(
        r#"
#![rustc_coherence_is_core]

impl i32 {
    pub fn int_method(self) {}
}
impl f64 {
    pub fn float_method(self) {}
}

fn foo() {
    1.$0
}
    "#,
        expect![[r#"
            me int_method() fn(self)
            sn box    Box::new(expr)
            sn call   function(expr)
            sn const        const {}
            sn dbg        dbg!(expr)
            sn dbgr      dbg!(&expr)
            sn deref           *expr
            sn match   match expr {}
            sn ref             &expr
            sn refm        &mut expr
            sn return    return expr
            sn unsafe      unsafe {}
        "#]],
    );
}

#[test]
fn deref_assign_completion() {
    // Test that completion after `*self = ` suggests the bare enum variants, not references
    // This is a regression test for https://github.com/rust-lang/rust-analyzer/issues/XXXXX
    //cov_mark::check!(expected_type_bin_expr);
    check(
        r#"
enum State {
    Stop(()),
    Running(u32),
}

impl State {
    fn test(&mut self) {
        *self = $0
    }
}
"#,
        expect![[r#"
            en State               State
            me self.test() fn(&mut self)
            lc self           &mut State
            sp Self                State
            bt u32                   u32
            kw const
            kw crate::
            kw false
            kw for
            kw if
            kw if let
            kw loop
            kw match
            kw return
            kw self::
            kw true
            kw unsafe
            kw while
            kw while let
        "#]],
    );
}
